# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import pymysql
import json

def lambda_handler(event, context):
    # Database connection configuration
    db_config = {
        'host': 'your-rds-endpoint',
        'user': 'your-username',
        'password': 'your-password',
        'database': 'your-database'
    }
    
    # Extract search parameters from the event
    search_params = event.get('queryStringParameters', {})
    
    # Construct SQL query dynamically based on search parameters
    sql = "SELECT * FROM products WHERE 1=1"
    conditions = []
    values = []
    
    if 'name' in search_params:
        conditions.append("name LIKE %s")
        values.append(f"%{search_params['name']}%")
        
    if 'price_min' in search_params and search_params['price_min'].isdigit():
        conditions.append("price >= %s")
        values.append(int(search_params['price_min']))
    
    if 'price_max' in search_params and search_params['price_max'].isdigit():
        conditions.append("price <= %s")
        values.append(int(search_params['price_max']))

    if conditions:
        sql += " AND " + " AND ".join(conditions)
    
    # Connect to the database and execute the query
    try:
        connection = pymysql.connect(**db_config)
        cursor = connection.cursor(pymysql.cursors.DictCursor)
        cursor.execute(sql, values)
        
        results = cursor.fetchall()
        cursor.close()
        connection.close()
        
        return {
            'statusCode': 200,
            'body': json.dumps(results),
            'headers': {
                'Content-Type': 'application/json'
            }
        }
    except pymysql.MySQLError as e:
        print(f"Error: {e}")
        return {
            'statusCode': 500,
            'body': json.dumps({'error': str(e)}),
            'headers': {
                'Content-Type': 'application/json'
            }
        }